FROM jsonb_to_recordset('[{"id": "cap-111-chinese-001", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-111-chinese", "question_type": "single_choice", "question_text": "這張圖最可能在傳達下列何種訊息？", "options": ["透過大量傳播，知識就會變成真理", "與其獨自苦讀，不如多與他人交流", "反覆誦讀，有助於將資訊內化為大腦深層的記憶", "能統整所學並轉述給別人，才算是真正掌握知識"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "a6fe6a465aa1", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 1, "raw_text": "1.\n\n\n\n\n     這張圖最可能在傳達下列何種訊息？\n     (A)透過大量傳播，知識就會變成真理\n     (B)與其獨自苦讀，不如多與他人交流\n     (C)反覆誦讀，有助於將資訊內化為大腦深層的記憶\n     (D)能統整所學並轉述給別人，才算是真正掌握知識\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-chinese-002", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-111-chinese", "question_type": "single_choice", "question_text": "黃醫師的眼科診所開業，親友們登門慶賀。君翰帶來一方寫著「杏林之\n光」的匾額，聊表心意。思涵見狀馬上說：「如果寫『近悅遠來』更好。」\n偉同則說：「可是，我覺得『眾望所歸』更恰當。」最後嘉恩才說：「其\n實，『桃李芬芳』才是最合適的選擇。」\n根據這段對話，誰的做法或說法最恰當？", "options": ["君翰", "思涵", "偉同", "嘉恩"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "a6fe6a465aa1", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 2, "raw_text": "2.     黃醫師的眼科診所開業，親友們登門慶賀。君翰帶來一方寫著「杏林之\n     光」的匾額，聊表心意。思涵見狀馬上說：「如果寫『近悅遠來』更好。」\n     偉同則說：「可是，我覺得『眾望所歸』更恰當。」最後嘉恩才說：「其\n     實，『桃李芬芳』才是最合適的選擇。」\n     根據這段對話，誰的做法或說法最恰當？\n     (A)君翰   (B)思涵   (C)偉同      (D)嘉恩\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-chinese-003", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-111-chinese", "question_type": "single_choice", "question_text": "「臺灣原住民的布只有形制屬傳統或較現代的分別，像圓領的剪裁、鈕扣和棉布的使\n用等，都是受漢人的影響而來。泰雅族的貝珠鈴衣，是貝珠串底下加銅鈴裝飾，銅\n鈴也是和漢人交易而來。日治時代的原住民服裝，還出現以漢人棉布做底、日本布\n做袖口、原住民圖案做主要裝飾的混搭法。」這段文字的主旨最可能是下列何者？", "options": ["不同文化的碰撞，可融合並產生新的火花", "外來文化的入侵，讓在地的傳統文化日漸消失", "臺灣原住民的文化，影響了漢人與日本人的穿著", "觀察不同族群的服飾，就能了解不同文化的差異"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "a6fe6a465aa1", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 3, "raw_text": "3. 「臺灣原住民的布只有形制屬傳統或較現代的分別，像圓領的剪裁、鈕扣和棉布的使\n    用等，都是受漢人的影響而來。泰雅族的貝珠鈴衣，是貝珠串底下加銅鈴裝飾，銅\n    鈴也是和漢人交易而來。日治時代的原住民服裝，還出現以漢人棉布做底、日本布\n    做袖口、原住民圖案做主要裝飾的混搭法。」這段文字的主旨最可能是下列何者？\n    (A)不同文化的碰撞，可融合並產生新的火花\n    (B)外來文化的入侵，讓在地的傳統文化日漸消失\n    (C)臺灣原住民的文化，影響了漢人與日本人的穿著\n    (D)觀察不同族群的服飾，就能了解不同文化的差異\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-chinese-004", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-111-chinese", "question_type": "single_choice", "question_text": "下表中的「獸」字依序最可能為何種字體？", "options": ["金文 → 楷書 → 小篆 → 隸書", "金文 → 小篆 → 隸書 → 楷書", "小篆 → 隸書 → 金文 → 楷書", "小篆 → 金文 → 楷書 → 隸書"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "a6fe6a465aa1", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 4, "raw_text": "4.   下表中的「獸」字依序最可能為何種字體？\n\n\n\n\n     (A)金文 → 楷書 → 小篆 → 隸書\n     (B)金文 → 小篆 → 隸書 → 楷書\n     (C)小篆 → 隸書 → 金文 → 楷書\n     (D)小篆 → 金文 → 楷書 → 隸書\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-chinese-005", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-111-chinese", "question_type": "single_choice", "question_text": "「過去賭客玩拉霸機時，需要把紙鈔塞進機器裡，所以會看見皮夾裡的鈔票越\n來越少，能提醒自己適時收手。但現在他們用卡片玩拉霸機，卡片僅會記錄\n他們的輸贏情況。賭客難以意識到自己正不斷輸錢，只能隱約記得花了多少\n錢。」這段文字的主旨與下列何者最接近？", "options": ["欲望會創造新的發明", "科技的進步使生活更便利", "長期沉溺於賭博之中容易讓人迷失自我", "不用現金支付使人對花錢的感受變得較遲鈍"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "a6fe6a465aa1", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 5, "raw_text": "5. 「過去賭客玩拉霸機時，需要把紙鈔塞進機器裡，所以會看見皮夾裡的鈔票越\n    來越少，能提醒自己適時收手。但現在他們用卡片玩拉霸機，卡片僅會記錄\n    他們的輸贏情況。賭客難以意識到自己正不斷輸錢，只能隱約記得花了多少\n    錢。」這段文字的主旨與下列何者最接近？\n    (A)欲望會創造新的發明\n    (B)科技的進步使生活更便利\n    (C)長期沉溺於賭博之中容易讓人迷失自我\n    (D)不用現金支付使人對花錢的感受變得較遲鈍\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-chinese-006", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-111-chinese", "question_type": "single_choice", "question_text": "下列體育新聞的說明何者錯誤？", "options": ["東道主法國隊屈居第二：法國是主辦國", "我國九局下逆轉，一分氣走韓國：我國轉輸為贏", "波多黎各選手爆冷門奪金：各界看好波多黎各選手奪金", "我國女將輕取哥倫比亞，晉級八強：我國女將大勝哥倫比亞"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "a6fe6a465aa1", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 6, "raw_text": "6.   下列體育新聞的說明何者錯誤？\n     (A)東道主法國隊屈居第二：法國是主辦國\n     (B)我國九局下逆轉，一分氣走韓國：我國轉輸為贏\n     (C)波多黎各選手爆冷門奪金：各界看好波多黎各選手奪金\n     (D)我國女將輕取哥倫比亞，晉級八強：我國女將大勝哥倫比亞\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-chinese-007", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-111-chinese", "question_type": "single_choice", "question_text": "「敘述記憶是件難事。記憶是一個整體，敘述的時候必須選擇將它一片片的切\n甲 切下來後就再也拼不完整了，就算拼湊起來了 乙\n下，即使是一塊肉、一棵菜甲\n也只算是死的標本，生命已蕩然 丙 何況記憶大部分的時候更像一陣風，來無影\n去無蹤的，要想將風片切下來，豈不完全是一場徒勞嗎 丁 」這段文字中的甲、\n乙、丙、丁四處，何者最適合使用標點符號中的句號？", "options": ["甲", "乙", "丙", "丁"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "a6fe6a465aa1", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 7, "raw_text": "7. 「敘述記憶是件難事。記憶是一個整體，敘述的時候必須選擇將它一片片的切\n               甲 切下來後就再也拼不完整了，就算拼湊起來了 乙\n   下，即使是一塊肉、一棵菜甲\n   也只算是死的標本，生命已蕩然 丙 何況記憶大部分的時候更像一陣風，來無影\n   去無蹤的，要想將風片切下來，豈不完全是一場徒勞嗎 丁 」這段文字中的甲、\n   乙、丙、丁四處，何者最適合使用標點符號中的句號？\n   (A)甲   (B)乙    (C)丙    (D)丁\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-chinese-008", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-111-chinese", "question_type": "single_choice", "question_text": "陸公嘗於市遇一佳硯，議價未定。既還邸，使門人往，以一金易歸。門\n人持硯歸，公訝其不類。門人堅證其是。公曰：「向觀硯有鴝鵒眼，今何無\n之？」答曰：「吾嫌其微凸，路遇石工，令磨而平之。」公大惋惜。\n下列關於故事中人物的敘述，何者最恰當？", "options": ["門人買錯硯臺卻不知道", "陸公惋惜是因石工技藝不佳", "門人請人磨平硯眼是自作聰明", "陸公對門人購硯的價格感到驚訝"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "a6fe6a465aa1", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 8, "raw_text": "8.     陸公嘗於市遇一佳硯，議價未定。既還邸，使門人往，以一金易歸。門\n     人持硯歸，公訝其不類。門人堅證其是。公曰：「向觀硯有鴝鵒眼，今何無\n     之？」答曰：「吾嫌其微凸，路遇石工，令磨而平之。」公大惋惜。\n     下列關於故事中人物的敘述，何者最恰當？\n     (A)門人買錯硯臺卻不知道\n     (B)陸公惋惜是因石工技藝不佳\n     (C)門人請人磨平硯眼是自作聰明\n     (D)陸公對門人購硯的價格感到驚訝\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-chinese-009", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-111-chinese", "question_type": "single_choice", "question_text": "「美國有名男子在家中裝攝影機，24小時在網路上播放他的生活，因此成為\n名人，甚且登上雜誌封面。這透露著有些人不再介意被窺視，甚至樂於被窺\n視。人有時會覺得孤寂，希望被注意，讓人覺得自己很重要。那些被窺視的\n人，既然知道鏡頭在哪裡，是否會有表演的性質呢？」根據這段文字，下列\n何者最接近作者的觀點？", "options": ["大眾的隱私權常常不受到尊重", "網路直播者多少帶有表演性質", "滿足他人偷窺欲就可成為名人", "孤寂的人總是害怕他人的眼光"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "a6fe6a465aa1", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 9, "raw_text": "9. 「美國有名男子在家中裝攝影機，24小時在網路上播放他的生活，因此成為\n   名人，甚且登上雜誌封面。這透露著有些人不再介意被窺視，甚至樂於被窺\n   視。人有時會覺得孤寂，希望被注意，讓人覺得自己很重要。那些被窺視的\n   人，既然知道鏡頭在哪裡，是否會有表演的性質呢？」根據這段文字，下列\n   何者最接近作者的觀點？\n   (A)大眾的隱私權常常不受到尊重\n   (B)網路直播者多少帶有表演性質\n   (C)滿足他人偷窺欲就可成為名人\n   (D)孤寂的人總是害怕他人的眼光\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-chinese-010", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-111-chinese", "question_type": "single_choice", "question_text": "「名不可以倖取也。天下之事，固有外似而中實不然者。倖其似而竊其名，非\n不可以欺一時，然他日人即其似而求其真，則情現實吐，無不立敗。」下列\n何者最能與這段文字的意旨相呼應？", "options": ["因其貌不揚被小看，沒想到靠著精湛演技成為影帝", "不勞而獲的錢財，因為來得容易，往往被輕易揮霍", "以作弊手段考上名校，最後卻因適應不良而中輟學業", "當不切實際的夢想碰到冷酷的現實，也只能化為泡影"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "a6fe6a465aa1", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 10, "raw_text": "10. 「名不可以倖取也。天下之事，固有外似而中實不然者。倖其似而竊其名，非\n    不可以欺一時，然他日人即其似而求其真，則情現實吐，無不立敗。」下列\n    何者最能與這段文字的意旨相呼應？\n    (A)因其貌不揚被小看，沒想到靠著精湛演技成為影帝\n    (B)不勞而獲的錢財，因為來得容易，往往被輕易揮霍\n    (C)以作弊手段考上名校，最後卻因適應不良而中輟學業\n    (D)當不切實際的夢想碰到冷酷的現實，也只能化為泡影\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-chinese-011", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-111-chinese", "question_type": "single_choice", "question_text": "根據這則說明，下列做法何者最符合健康概念？\n背包與健康\n(一)重量：背包後背時，內容\n物的重量最好在體重10％\n以內，側背時則建議低於\n5％。\n(二)背法：背包的背帶越短、\n靠身體越近，力量承受度\n越小，背起來越輕鬆。\n(三)放法：最重的東西應放在\n背包中間，步行時比較不\n會影響身體的姿勢。", "options": ["", "", "", ""], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "a6fe6a465aa1", "answer_pdf_sha1": "5db25b41f664", "flags": ["option_incomplete", "option_image"], "parse_confidence": 0.4, "original_question_number": 11, "raw_text": "11.                     根據這則說明，下列做法何者最符合健康概念？\n          背包與健康\n      (一)重量：背包後背時，內容\n         物的重量最好在體重10％\n         以內，側背時則建議低於\n         5％。\n      (二)背法：背包的背帶越短、\n         靠身體越近，力量承受度\n         越小，背起來越輕鬆。\n      (三)放法：最重的東西應放在\n         背包中間，步行時比較不\n         會影響身體的姿勢。\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-chinese-012", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-111-chinese", "question_type": "single_choice", "question_text": "下列選項「」中的字，何組讀音相同？", "options": ["悲傷哽「咽」／食不下「咽」", "悶不「吭」聲／引「吭」高歌", "語帶「禪」機／「禪」讓政治", "「撒」謊成習／恃寵「撒」嬌"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "a6fe6a465aa1", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 12, "raw_text": "12. 下列選項「」中的字，何組讀音相同？\n    (A)悲傷哽「咽」／食不下「咽」\n    (B)悶不「吭」聲／引「吭」高歌\n    (C)語帶「禪」機／「禪」讓政治\n    (D)「撒」謊成習／恃寵「撒」嬌\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-chinese-013", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-111-chinese", "question_type": "single_choice", "question_text": "「所謂中菜西吃，是將原本大盤共享且同桌擺放的宴席菜式，改為西餐般一人一\n份、一道道依序送上。但中菜向來比西菜更講究沸熱燙口，分開上菜後，熱度鑊\n氣全消。其次，拋卻一桌多道同食，享受各種味道交錯的樂趣。更嚴重的是，\n為了美觀便利，連烹調手法都起了變化。例如原本該整魚整肉整蔬大鍋蒸煮煨\n燉，卻改為小塊小盅個別處理，光這點就足以讓同冶一爐、渾然一體之味傷損逸\n散。」根據這段文字，作者不愛中菜西吃的原因最不可能包含下列何者？", "options": ["中式食法多道並陳，西式則否", "中菜較西菜更講究菜餚的熱度", "西餐的上菜速度及料理方式費時又費工", "西式食法盡失中菜大鍋烹煮整肉的風味"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "a6fe6a465aa1", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 13, "raw_text": "13. 「所謂中菜西吃，是將原本大盤共享且同桌擺放的宴席菜式，改為西餐般一人一\n     份、一道道依序送上。但中菜向來比西菜更講究沸熱燙口，分開上菜後，熱度鑊\n     氣全消。其次，拋卻一桌多道同食，享受各種味道交錯的樂趣。更嚴重的是，\n     為了美觀便利，連烹調手法都起了變化。例如原本該整魚整肉整蔬大鍋蒸煮煨\n     燉，卻改為小塊小盅個別處理，光這點就足以讓同冶一爐、渾然一體之味傷損逸\n     散。」根據這段文字，作者不愛中菜西吃的原因最不可能包含下列何者？\n     (A)中式食法多道並陳，西式則否\n     (B)中菜較西菜更講究菜餚的熱度\n     (C)西餐的上菜速度及料理方式費時又費工\n     (D)西式食法盡失中菜大鍋烹煮整肉的風味\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-chinese-014", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-111-chinese", "question_type": "single_choice", "question_text": "「修身以為弓，矯思以為矢，立義以為的，定而後發，發必中矣。」句中「矯」\n字的意義，與下列何者最接近？", "options": ["「矯」世勵俗", "「矯」若遊龍", "「矯」捷身手", "「矯」託天命"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "a6fe6a465aa1", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 14, "raw_text": "14. 「修身以為弓，矯思以為矢，立義以為的，定而後發，發必中矣。」句中「矯」\n    字的意義，與下列何者最接近？\n    (A)「矯」世勵俗      (B)「矯」若遊龍\n    (C)「矯」捷身手      (D)「矯」託天命\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
